// numero10.js con la estructura de bangchan_an01.js
(function(){
  // --- ORIGINAL CHUNKS (copiado de tu archivo original) ---
  const ORIGINAL_CHUNKS = [
    //Frame 1
    "",
    //Frame 2
    "",
    //Frame 3
    "",    
    //Frame 4
    "",    
    //Frame 5
    "",
    //Frame 6
    "",    
    //Frame 7
    "",
    //Frame 8
    "",
    //Frame 9
    "",
    //Frame 10
    "",
    //Frame 11
    "",    
    //Frame 12
    "",    
    //Frame 13
    "",
    //Frame 14
    "",    
    //Frame 15
    "",
    //Frame 16
    "",
    ];

  // --- helpers ---
  function cleanHex(s){ return String(s||'').replace(/[^0-9A-Fa-f]/g,'').toUpperCase(); }
  function padToFrame(hex){
    const FRAME_HEX_LEN = 2048 * 2; // 4096 hex chars = 2048 bytes
    const h = cleanHex(hex);
    if (h.length >= FRAME_HEX_LEN) return h.substr(0, FRAME_HEX_LEN);
    return h.padEnd(FRAME_HEX_LEN, '0');
  }

  function buildFramesByConcatenation(chunks){
    // concat y luego cortar en bloques de FRAME_HEX_LEN
    const FRAME_HEX_LEN = 2048 * 2;
    const all = chunks.map(cleanHex).join('');
    const frames = [];
    for(let i=0; i + FRAME_HEX_LEN <= all.length; i += FRAME_HEX_LEN){
      frames.push(all.substr(i, FRAME_HEX_LEN));
    }
    // si quedó resto, pad y añadir
    const rem = all.length % FRAME_HEX_LEN;
    if(rem > 0) frames.push(all.substr(all.length - rem).padEnd(FRAME_HEX_LEN, '0'));
    return frames;
  }

  function buildFramesByGrouping(chunks){
    // acumula chunks hasta formar frames completos (misma lógica que antes)
    const FRAME_HEX_LEN = 2048 * 2;
    const frames = [];
    let buf = '';
    for(let raw of chunks){
      const h = cleanHex(raw);
      if(!h) continue;
      buf += h;
      while(buf.length >= FRAME_HEX_LEN){
        frames.push(buf.substr(0, FRAME_HEX_LEN));
        buf = buf.substr(FRAME_HEX_LEN);
      }
    }
    if(buf.length > 0) frames.push(buf.padEnd(FRAME_HEX_LEN, '0'));
    return frames;
  }

  // --- Interpretaciones a probar ---
  // Puede ocurrir que ORIGINAL_CHUNKS sea [ "<​bighex1>", "<​bighex2>", ... ] (cada entrada ya frame)
  // o [ ["chunk1","chunk2",... ] ] (un único elemento que es array con chunks)
  // o [ "chunk1", "chunk2", ... ] (chunks simples)

  let candidateFrames = [];
  // Normalize input into array-of-strings or array-of-array
  const entries = ORIGINAL_CHUNKS.slice();

  // Si la estructura real fuera un array que contiene un solo array (era tu caso),
  // intentaremos 3 caminos:
  // A) si entries[0] es string pero parece ser una JSON-ish que contenía sub-arrays? (ya lo pasamos)
  // B) si entries.length === 1 && inner is array -> innerItems = entries[0]
  // C) si entries is plain list -> handle directly

  // Detect nested array encoded as single string? (no en tu caso) - skip

  // Caso: si entries[0] es string que representa un array (no aplicable aquí)
  // Ahora detectemos si el primer elemento contiene múltiples frames (por ser un array literal)
  let first = entries[0];
  // If first contains only hex chars and looks like a representation of multiple items separated by something, skip: here it's plain chunk strings
  // However in your original file, the structure was MIS_ANIMACIONES = { "numero10": [ [chunk1,chunk2,...] ] }
  // So assume ORIGINAL_CHUNKS actually are chunk strings as here.

  // Strategy 1: treat each ORIGINAL_CHUNKS item as a frame directly
  const strategy1 = entries.map(e => padToFrame(e));

  // Strategy 2: if entries.length === 1 and its content is itself a list (we can't detect nested JS arrays here),
  // but we check if entries[0] contains many '0000' patterns indicating it includes concatenated chunks —
  // Also attempt to parse if entries[0] contains embedded separators (not expected).
  const strategy2 = buildFramesByGrouping(entries);

  // Strategy 3: concat todo y cortar en bloques
  const strategy3 = buildFramesByConcatenation(entries);

  // Prepare diagnostics
  function diag(name, frames){
    console.log(`${name}: frames=${frames.length} ; first-len=${frames[0]?.length||0}`);
    for(let i=0;i<Math.min(frames.length,5);i++){
      console.log(`${name} frame[${i}] len=${frames[i].length} sample=${frames[i].substr(0,80)}...`);
    }
  }

  diag('strategy1_eachItemAsFrame', strategy1);
  diag('strategy2_groupChunksToFrames', strategy2);
  diag('strategy3_joinAndCut', strategy3);

  // Choose best: prefer the one that gives more than 1 frame; if multiple give >1 pick the one with frames all ==4096
  function chooseBest(a,b,c){
    const FRAME_HEX_LEN = 2048*2;
    const score = (arr) => {
      if(!arr || arr.length===0) return 0;
      // base score: number of frames * fraction of frames with exact length
      let exact = arr.filter(f => f.length === FRAME_HEX_LEN).length;
      return arr.length * (1 + exact/arr.length);
    };
    const scores = [
      {name:'strategy1', s:score(a), frames:a},
      {name:'strategy2', s:score(b), frames:b},
      {name:'strategy3', s:score(c), frames:c}
    ];
    scores.sort((x,y)=>y.s - x.s);
    console.log('chooseBest scores', scores.map(s=>({n:s.name,score:s.s,frames: s.frames.length})));
    return scores[0].frames;
  }

  const chosen = chooseBest(strategy1, strategy2, strategy3);

  // Export to window
  const MIS_ANIMACIONES_NUMERO10 = { "numero10": chosen };
  const MIS_DISENOS_NUMERO10 = { "numero10": ORIGINAL_CHUNKS.slice() };

  if (typeof window !== 'undefined') {
    window.MIS_ANIMATIONS = Object.assign(window.MIS_ANIMATIONS || {}, MIS_ANIMACIONES_NUMERO10);
    window.MIS_DISENOS = Object.assign(window.MIS_DISENOS || {}, MIS_DISENOS_NUMERO10);
  }

  console.log('runit: final frames exported =', chosen.length);
  for(let i=0;i<chosen.length;i++){
    console.log(`frame[${i}] len=${chosen[i].length} sampleStart=${chosen[i].substr(0,80)}...`);
  }
})();
